    const ctx = gsap.context(() => {
      ScrollTrigger.create({
        trigger: ".section-1",
        start: "top center",
        onEnter: () => {
          gsap.to(containerRef.current, { backgroundColor: "#ffffff", color: "black", duration: 0.8, ease: "power2.out" });
          setTextColor("black");
          setTheme("#ffffff");
        },
        onLeaveBack: () => {
          gsap.to(containerRef.current, { backgroundColor: "#000000", color: "white", duration: 0.8, ease: "power2.out" });
          setTextColor("white");
          setTheme("#000000");
        },
      });
      ScrollTrigger.create({
        trigger: ".section-4",
        start: "top center",
        onEnter: () => {
          gsap.to(containerRef.current, { backgroundColor: "#ffffff", color: "black" });
          setTextColor("black");
          setTheme("#ffffff");
        },
        onLeaveBack: () => {
          gsap.to(containerRef.current, { backgroundColor: "#000000", color: "white" });
          setTextColor("white");
          setTheme("#000000");
        },
      });
      ScrollTrigger.create({
        trigger: ".section-5",
        start: "top center",
        onEnter: () => {
          gsap.to(containerRef.current, { backgroundColor: "#000000", color: "white", duration: 0.8, ease: "power2.out" });
          setTextColor("white");
          setTheme("#000000");
        },
        onLeaveBack: () => {
          gsap.to(containerRef.current, { backgroundColor: "#ffffff", color: "black", duration: 0.8, ease: "power2.out" });
          setTextColor("black");
          setTheme("#ffffff");
        },
      });
    });
    return () => ctx.revert();
  }, []);

