      <section className="w-screen section-5 h-full py-[2vw]">
        <div className="w-full flex items-center justify-center py-[3vw]">
          <h2 className="text-[3.5vw] text-center leading-[1.2]">Playful Arrows</h2>
        </div>
        <ArrowsPlay />
      </section>
    </div>
  );
