"use client";
import React, { useEffect, useRef } from "react";

export function ArrowsLimit({ rows = 5, columns = 10 }) {
  const canvasRef = useRef(null);
  const mouseRef = useRef({ x: 0, y: 0 });
  const arrowsRef = useRef([]);
  const animationFrameRef = useRef(null);

  class Point {
    constructor(x, y) {
      this.x = x || 0;
      this.y = y || 0;
    }
  }

  class Arrow {
    constructor(position) {
      this.pos = position;
      this.dx = 0;
      this.dy = 0;
      this.angle = 0;
      this.ease = 0.1;
    }

    update(mouseX, mouseY) {
      const targetDx = mouseX - this.pos.x;
      const targetDy = mouseY - this.pos.y;
      this.dx += (targetDx - this.dx) * this.ease * 0.35;
      this.dy += (targetDy - this.dy) * this.ease * 0.35;
      this.angle = Math.atan2(this.dy, this.dx);
    }

    draw(ctx) {
      ctx.save();
      ctx.translate(this.pos.x, this.pos.y);
      ctx.rotate(this.angle);
      ctx.beginPath();
      ctx.moveTo(50, 0);
      ctx.lineTo(-50, 0);
      ctx.moveTo(50, 0);
      ctx.lineTo(10, -40);
      ctx.moveTo(50, 0);
      ctx.lineTo(10, 40);
      ctx.lineWidth = 2;
      ctx.strokeStyle = "white";
      ctx.stroke();
      ctx.restore();
    }
  }

  const initializeArrows = (canvas) => {
    const arrows = [];
    const spacingX = canvas.width / (columns + 1);
    const spacingY = canvas.height / (rows + 1);
    for (let y = 1; y <= rows; y++) {
      for (let x = 1; x <= columns; x++) {
        arrows.push(new Arrow(new Point(x * spacingX, y * spacingY)));
      }
    }
    return arrows;
  };

  const handleResize = () => {
    const canvas = canvasRef.current;
    if (canvas) {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      arrowsRef.current = initializeArrows(canvas);
    }
  };

  const handleMouseMove = (e) => {
    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    if (
      e.clientX >= rect.left &&
      e.clientX <= rect.right &&
      e.clientY >= rect.top &&
      e.clientY <= rect.bottom
    ) {
      mouseRef.current = {
        x: e.clientX - rect.left,
        y: e.clientY - rect.top,
      };
    }
  };

  const main = () => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    arrowsRef.current.forEach((arrow) => {
      arrow.update(mouseRef.current.x, mouseRef.current.y);
      arrow.draw(ctx);
    });
    animationFrameRef.current = requestAnimationFrame(main);
  };

  useEffect(() => {
    const canvas = canvasRef.current;
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    arrowsRef.current = initializeArrows(canvas);
    window.addEventListener("resize", handleResize);
    window.addEventListener("mousemove", handleMouseMove);
    main();
    return () => {
      window.removeEventListener("resize", handleResize);
      window.removeEventListener("mousemove", handleMouseMove);
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [rows, columns]);

  return (
    <div className="w-full h-full">
      <canvas ref={canvasRef} className="w-full h-full" />
    </div>
  );
}

"use client";
import React, { useEffect, useRef } from "react";

export function ArrowsOpacity() {
  const canvasRef = useRef(null);
  const requestIdRef = useRef(null);
  const arrowArrRef = useRef([]);
  const mouseRef = useRef({ x: 0, y: 0 });

  class Point {
    constructor(x, y) {
      this.x = x || 0;
      this.y = y || 0;
    }
  }

  class Arrow {
    constructor(position) {
      this.pos = position;
      this.dx = 0;
      this.dy = 0;
      this.angle = 0;
      this.dist = 0;
    }

    update(mx, my) {
      this.dx = mx - this.pos.x;
      this.dy = my - this.pos.y;
      this.dist = Math.sqrt(this.dx * this.dx + this.dy * this.dy);
      this.angle = Math.atan2(this.dy, this.dx);
    }

    draw(ctx) {
      ctx.save();
      ctx.translate(this.pos.x, this.pos.y);
      ctx.rotate(this.angle);
      ctx.beginPath();
      ctx.moveTo(30, 0);
      ctx.lineTo(-30, 0);
      ctx.moveTo(30, 0);
      ctx.lineTo(5, -30);
      ctx.moveTo(30, 0);
      ctx.lineTo(5, 30);
      ctx.lineWidth = 5;
      const alpha = 1 - this.dist / 300;
      ctx.strokeStyle = `rgba(0, 0, 0, ${Math.max(0, alpha)})`;
      ctx.stroke();
      ctx.restore();
    }
  }

  const initializeArrows = (canvas) => {
    arrowArrRef.current = [];
    for (let y = 0; y < canvas.height / 20; y++) {
      for (let x = 0; x < canvas.width / 50; x++) {
        arrowArrRef.current.push(new Arrow(new Point(x * 75, y * 75)));
      }
    }
  };

  const handleResize = () => {
    const canvas = canvasRef.current;
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    initializeArrows(canvas);
  };

  const handleMouseMove = (e) => {
    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    const mouseX = (e.clientX - rect.left) * scaleX;
    const mouseY = (e.clientY - rect.top) * scaleY;
    if (mouseX >= 0 && mouseX <= canvas.width && mouseY >= 0 && mouseY <= canvas.height) {
      mouseRef.current = { x: mouseX, y: mouseY };
    }
  };

  const animate = () => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    const { x: mx, y: my } = mouseRef.current;
    for (let y = 0; y < canvas.height / 20; y++) {
      for (let x = 0; x < canvas.width / 50; x++) {
        const arrow = arrowArrRef.current[y * 10 + x];
        if (arrow) {
          arrow.update(mx, my);
          arrow.draw(ctx);
        }
      }
    }
    requestIdRef.current = requestAnimationFrame(animate);
  };

  useEffect(() => {
    const canvas = canvasRef.current;
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    initializeArrows(canvas);
    window.addEventListener("resize", handleResize);
    canvas.addEventListener("mousemove", handleMouseMove);
    requestIdRef.current = requestAnimationFrame(animate);
    return () => {
      window.removeEventListener("resize", handleResize);
      canvas.removeEventListener("mousemove", handleMouseMove);
      if (requestIdRef.current) cancelAnimationFrame(requestIdRef.current);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      style={{ width: "100%", height: "100%", pointerEvents: "auto" }}
    />
  );
}

"use client";
import React, { useEffect, useRef } from "react";

export function ArrowsPlay() {
  const canvasRef = useRef(null);
  const mouseRef = useRef({ x: 0, y: 0 });
  const arrowsRef = useRef([]);
  const animationFrameRef = useRef(null);
  const divRef = useRef(null);

  class Point {
    constructor(x, y) {
      this.x = x || 0;
      this.y = y || 0;
    }
  }

  class Arrow {
    constructor(position) {
      this.pos = position;
      this.dx = 0;
      this.dy = 0;
      this.angle = 0;
    }

    update(mouseX, mouseY) {
      this.dx = mouseX - this.pos.x;
      this.dy = mouseY - this.pos.y;
      this.angle = Math.atan2(this.dy, this.dx);
    }

    draw(ctx) {
      ctx.save();
      ctx.translate(this.pos.x, this.pos.y);
      ctx.rotate(this.angle);
      ctx.beginPath();
      ctx.moveTo(30, 0);
      ctx.lineTo(-30, 0);
      ctx.moveTo(30, 0);
      ctx.lineTo(10, -20);
      ctx.moveTo(30, 0);
      ctx.lineTo(10, 20);
      ctx.lineWidth = 2.5;
      ctx.strokeStyle = "white";
      ctx.stroke();
      ctx.restore();
    }
  }

  const initializeArrows = (canvas) => {
    const arrows = [];
    const spacing = 120;
    const cols = Math.floor(canvas.width / spacing);
    const rows = Math.floor(canvas.height / spacing);
    const xPadding = (canvas.width - cols * spacing) / 2;
    const yPadding = (canvas.height - rows * spacing) / 2;

    const divRect = divRef.current.getBoundingClientRect();
    const canvasRect = canvas.getBoundingClientRect();
    const divLeft = divRect.left - canvasRect.left;
    const divRight = divRect.right - canvasRect.left;
    const divTop = divRect.top - canvasRect.top;
    const divBottom = divRect.bottom - canvasRect.top;

    for (let y = 0; y <= rows; y++) {
      for (let x = 0; x <= cols; x++) {
        const arrowPos = new Point(x * spacing + xPadding, y * spacing + yPadding);
        if (
          arrowPos.x >= divLeft &&
          arrowPos.x <= divRight &&
          arrowPos.y >= divTop &&
          arrowPos.y <= divBottom
        ) {
          continue;
        }
        arrows.push(new Arrow(arrowPos));
      }
    }
    return arrows;
  };

  const handleResize = () => {
    const canvas = canvasRef.current;
    if (canvas) {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      arrowsRef.current = initializeArrows(canvas);
    }
  };

  const handleMouseMove = (e) => {
    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    if (
      e.clientX >= rect.left &&
      e.clientX <= rect.right &&
      e.clientY >= rect.top &&
      e.clientY <= rect.bottom
    ) {
      mouseRef.current = {
        x: e.clientX - rect.left,
        y: e.clientY - rect.top,
      };
    }
  };

  const main = () => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    arrowsRef.current.forEach((arrow) => {
      arrow.update(mouseRef.current.x, mouseRef.current.y);
      arrow.draw(ctx);
    });
    animationFrameRef.current = requestAnimationFrame(main);
  };

  useEffect(() => {
    const canvas = canvasRef.current;
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    arrowsRef.current = initializeArrows(canvas);
    window.addEventListener("resize", handleResize);
    window.addEventListener("mousemove", handleMouseMove);
    main();
    return () => {
      window.removeEventListener("resize", handleResize);
      window.removeEventListener("mousemove", handleMouseMove);
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, []);

  return (
    <div className="relative w-full h-full">
      <canvas ref={canvasRef} className="w-full h-full" style={{ cursor: "pointer" }} />
      <div
        ref={divRef}
        className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 z-10"
        style={{
          cursor: "pointer",
          height: "25vw",
          width: "35vw",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          backgroundColor: "transparent",
        }}
      >
        <h1 className="text-[18vw] text-white font-medium transition-all ease duration-500">
          Play
        </h1>
      </div>
    </div>
  );
}

"use client";
import React, { useEffect, useRef } from "react";

export function Arrows() {
  const canvasRef = useRef(null);
  const mouseRef = useRef({ x: 0, y: 0 });
  const arrowsRef = useRef([]);
  const animationFrameRef = useRef(null);

  class Point {
    constructor(x, y) {
      this.x = x || 0;
      this.y = y || 0;
    }
  }

  class Arrow {
    constructor(position) {
      this.pos = position;
      this.dx = 0;
      this.dy = 0;
      this.angle = 0;
      this.isHovered = false;
      this.originalPos = { ...position };
      this.targetPos = { ...position };
    }

    update(mouseX, mouseY) {
      this.dx = mouseX - this.pos.x;
      this.dy = mouseY - this.pos.y;
      this.angle = Math.atan2(this.dy, this.dx) * 0.95;

      const distance = Math.sqrt(
        Math.pow(mouseX - this.pos.x, 2) + Math.pow(mouseY - this.pos.y, 2)
      );
      const wasHovered = this.isHovered;
      this.isHovered = distance < 30;

      if (this.isHovered !== wasHovered) {
        if (this.isHovered) {
          arrowsRef.current.forEach((otherArrow) => {
            if (otherArrow !== this) {
              const dx = otherArrow.pos.x - this.pos.x;
              const dy = otherArrow.pos.y - this.pos.y;
              const dist = Math.sqrt(dx * dx + dy * dy);
              if (dist < 70) {
                const pushForce = (70 - dist) / 70;
                otherArrow.targetPos = {
                  x: otherArrow.originalPos.x + (dx / dist) * 20 * pushForce,
                  y: otherArrow.originalPos.y + (dy / dist) * 20 * pushForce,
                };
              }
            }
          });
        } else {
          arrowsRef.current.forEach((arrow) => {
            arrow.targetPos = { ...arrow.originalPos };
          });
        }
      }

      this.pos.x += (this.targetPos.x - this.pos.x) * 0.1;
      this.pos.y += (this.targetPos.y - this.pos.y) * 0.1;
    }

    draw(ctx) {
      ctx.save();
      ctx.translate(this.pos.x, this.pos.y);
      ctx.rotate(this.angle);
      ctx.beginPath();
      ctx.moveTo(20, 0);
      ctx.lineTo(-20, 0);
      ctx.moveTo(20, 0);
      ctx.lineTo(5, -15);
      ctx.moveTo(20, 0);
      ctx.lineTo(5, 15);
      ctx.lineWidth = this.isHovered ? 3 : 2;
      ctx.strokeStyle = "black";
      ctx.stroke();
      ctx.restore();
    }
  }

  const initializeArrows = (canvas) => {
    const arrows = [];
    const spacing = 50;
    const cols = Math.floor(canvas.width / spacing);
    const rows = Math.floor(canvas.height / spacing);
    const xPadding = (canvas.width - cols * spacing) / 2;
    const yPadding = (canvas.height - rows * spacing) / 2;
    for (let y = 0; y <= rows; y++) {
      for (let x = 0; x <= cols; x++) {
        arrows.push(
          new Arrow(new Point(x * spacing + xPadding, y * spacing + yPadding))
        );
      }
    }
    return arrows;
  };

  const handleResize = () => {
    const canvas = canvasRef.current;
    if (canvas) {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      arrowsRef.current = initializeArrows(canvas);
    }
  };

