"use client";
import React, { useEffect, useRef, useState } from "react";

export function Points() {
  const canvasRef = useRef(null);
  const mouseRef = useRef({ x: 0, y: 0 });
  const pointsRef = useRef([]);
  const animationFrameRef = useRef(null);
  const mouseEnteredRef = useRef(false);
  const [lineLength, setLineLength] = useState(0);
  const maxLineLength = 25;
  const easingSpeed = 0.05;

  class Point {
    constructor(x, y) {
      this.x = x || 0;
      this.y = y || 0;
    }

    draw(ctx, mouseX, mouseY) {
      if (mouseEnteredRef.current) {
        const dx = mouseX - this.x;
        const dy = mouseY - this.y;
        const distance = Math.sqrt(dx * dx + dy * dy);
        const unitX = dx / distance;
        const unitY = dy / distance;
        const lineEndX = this.x + unitX * lineLength;
        const lineEndY = this.y + unitY * lineLength;
        ctx.beginPath();
        ctx.moveTo(this.x, this.y);
        ctx.lineTo(lineEndX, lineEndY);
        ctx.strokeStyle = "black";
        ctx.lineWidth = 1.5;
        ctx.stroke();
      } else {
        ctx.beginPath();
        ctx.arc(this.x, this.y, 2, 0, Math.PI * 2);
        ctx.fillStyle = "black";
        ctx.fill();
      }
    }
  }

  const initializePoints = (canvas) => {
    const points = [];
    const spacing = 60;
    const cols = Math.floor(canvas.width / spacing);
    const rows = Math.floor(canvas.height / spacing);
    const xPadding = (canvas.width - cols * spacing) / 2;
    const yPadding = (canvas.height - rows * spacing) / 2;
    for (let y = 0; y <= rows; y++) {
      for (let x = 0; x <= cols; x++) {
        points.push(new Point(x * spacing + xPadding, y * spacing + yPadding));
      }
    }
    return points;
  };

  const handleResize = () => {
    const canvas = canvasRef.current;
    if (canvas) {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      pointsRef.current = initializePoints(canvas);
    }
  };

  const handleMouseMove = (e) => {
    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    mouseRef.current = {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY,
    };
  };

  const handleMouseEnter = () => {
    mouseEnteredRef.current = true;
  };

  const updateLineLength = () => {
    if (mouseEnteredRef.current && lineLength < maxLineLength) {
      setLineLength((prev) => Math.min(prev + easingSpeed, maxLineLength));
    } else if (!mouseEnteredRef.current && lineLength > 0) {
      setLineLength((prev) => Math.max(prev - easingSpeed, 0));
    }
  };

  const main = () => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    updateLineLength();
    pointsRef.current.forEach((point) => {
      point.draw(ctx, mouseRef.current.x, mouseRef.current.y);
    });
    animationFrameRef.current = requestAnimationFrame(main);
  };

  useEffect(() => {
    const canvas = canvasRef.current;
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    pointsRef.current = initializePoints(canvas);
    window.addEventListener("resize", handleResize);
    canvas.addEventListener("mousemove", handleMouseMove);
    canvas.addEventListener("mouseenter", handleMouseEnter);
    main();
    return () => {
      window.removeEventListener("resize", handleResize);
      canvas.removeEventListener("mousemove", handleMouseMove);
      canvas.removeEventListener("mouseenter", handleMouseEnter);
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [lineLength]);

  return (
    <div className="w-full h-full">
      <canvas ref={canvasRef} className="w-full h-full" style={{ cursor: "pointer" }} />
    </div>
  );
}
